<template>
  <div>
    <div id="uoloaddiv35" align="left">
      <el-button type="button" @click="dialogVisible = true" class="margingbot10">申请入驻电台</el-button>

      <el-dialog title="申请入驻:" :visible.sync="dialogVisible" width="30%">
        <div class="shenqingdiantai123">
