     // }
    },
    adjustVolume() {
      switch (this.volumeAdjust.vol1) {
        case 0:
          this.volumeAdjust.vol2 = 1;
          break;
        case 10:
          this.volumeAdjust.vol2 = 15;
          break;
        case 20:
          this.volumeAdjust.vol2 = 25;
          break;
        case 30:
          this.volumeAdjust.vol2 = 30;
          break;
        case 40:
