            }
          }.bind(this)
        )
        .catch(function(res) {
          console.log(res);
        });
      this.dialogVisible_adddevice2 = false;
    },
    adjustVolumes() {
      this.dialogVisible_adddevice4=false;
      switch (this.volumeAdjust.vol3) {
        case 0:
          this.volumeAdjust.vol4 = 1;
          break;
        case 10:
          this.volumeAdjust.vol4 = 15;
          break;
        case 20:
          this.volumeAdjust.vol4 = 25;
          break;
        case 30:
          this.volumeAdjust.vol4 = 30;
          break;
        case 40:
          this.volumeAdjust.vol4 = 35;
          break;
