          break;
        case 80:
          this.volumeAdjust.vol4 = 55;
          break;
        case 90:
          this.volumeAdjust.vol4 = 60;
          break;
        case 100:
          this.volumeAdjust.vol4 = 63;
      }
      console.log(this.volumeAdjust);
      var seedss=[];

      for(var si =0;si<this.volvalue.length;si++ ){
