      axios
        .post("/user/editvols", datadf).then(
          function(res) {
            if (res.data.res) {
              console.log(res.data);
              this.$notify.success({
                title: "Info",
                message: "修改成功",
                showClose: false
              });

              this.reflash_devlist();
            } else {
              console.log(res.data);
              this.$notify.success({
                title: "Info",
                message: "修改失败",
                showClose: false
              });
            }
          }.bind(this)
        )
        .catch(function(res) {
          console.log(res);
        });
      this.dialogVisible_adddevice2 = false;
