    open5() {
      this.$alert(this.save_backdata, "配置详情", {
        dangerouslyUseHTMLString: false
      });
    },
    handleClose_save_back() {},
    func_addone_device() {
      this.dialogVisible_adddevice = false;
      if (this.name_adddevice.trim() == "") {
        this.$notify.success({
          title: "Info",
          message: "设备名字不能为空",
          showClose: true
        });
        return;
      }
      if (
        this.seed_adddevice.trim() == "" ||
        this.seed_adddevice.trim().length != 32
      ) {
        this.$notify.success({
          title: "Info",
          message: "设备序列号 seed 不正确",
          showClose: true
        });
        return;
      }
      if(this.sqr_adddevice.trim() == "" ||  this.sqr_adddevice.trim().length != 32 ){
            this.$notify.success({
              title: 'Info',
              message: '设备序公钥 sqr 不正确',
              showClose: true
            });
            return;
      }

      let data = new FormData();
      data.append("id", sessionStorage.getItem("id"));
      data.append("token", sessionStorage.getItem("token"));
      data.append("name", this.name_adddevice);
      data.append("sn", this.seed_adddevice+"|"+this.sqr_adddevice);
      axios
        .post("/user/deviceadd", data)
        .then(
          function(res) {
            if (res.data.res) {
              this.$notify.success({
                title: "Info",
                message: "添加成功",
                showClose: false
              });
              this.reflash_devlist();
            } else {
              this.$notify.success({
                title: "Info",
                message: "添加设备出现异常",
                showClose: false
              });
            }
          }.bind(this)
        )
        .catch(function(res) {
          console.log(res);
        });
    },

    func_adddevic() {
      this.dialogVisible_adddevice = true;
    },
    func_savedevic() {
      const loading = this.$loading({
        lock: true,
        text: "Processing",
        spinner: "el-icon-loading",
        background: "rgba(0, 0, 0, 0.7)",
        target: document.querySelector(".div1")
      });



      axios
        .get("/create_config.php")
        .then(
          function(res) {
            if (res.data.res) {
              this.save_backdata = res.data.config;
              this.dialogVisible_save_back = true;
              loading.close();
            } else {
              this.$notify.success({
                title: "Info",
                message: "哪里出现错误了",
                showClose: false
              });
            }
          }.bind(this)
        )
        .catch(function(res) {
          console.log(res);
        });
    },
    deleteRow(index, rows) {
      let data = new FormData();
      data.append("id", sessionStorage.getItem("id"));
      data.append("token", sessionStorage.getItem("token"));
      data.append("snid", rows[index].id);
      axios
        .post("/user/deldevs", data )
        .then(
          function(res) {
            if (res.data.res) {
              this.$notify.success({
                title: "Info",
                message: "删除成功",
                showClose: false
              });
              rows.splice(index, 1);
              this.reflash_devlist();
            } else {
              this.$notify.success({
                title: "Info",
                message: "删除失败",
                showClose: false
              });
            }
          }.bind(this)
        )
        .catch(function(res){
          console.log(res);
        });
    },
    renameRow(index, rows) {
      let seed = rows[index].seed;
      let devid = rows[index].id;
      let username = sessionStorage.getItem("username");
      let passwd = sessionStorage.getItem("passwd");
      this.$prompt("New NAME:", "提示", {
