        inputPattern: /^[\u4e00-\u9fa5_a-zA-Z0-9]+$/,
        inputErrorMessage: "格式不正确"
      })
      .then(({ value }) => {
        if (value.length >= 30) {
          this.$message({
            type: "info",
            message: "名字输入不合规"
          });
          return;
        }
        console.log(value);

          let devid = rows[index].id;
          let data = new FormData();
          data.append("id", sessionStorage.getItem("id"));
          data.append("token", sessionStorage.getItem("token"));
          data.append("newname", value );
          data.append("devid"  , devid  );
          axios
            .post("/user/redevname", data )
            .then(
              function(res) {
                if (res.data.res) {
                  this.$notify.success({
                    title: "Info",
                    message: "修改成功",
                    showClose: false
                  });
                  rows.splice(index, 1);
                  this.reflash_devlist();
                } else {
                  this.$notify.success({
                    title: "Info",
