            .catch(function(res) {
              console.log(res);
            });
        })
        .catch(() => {
          this.$message({
            type: "info",
            message: "取消输入"
          });
        });
    },
    resnRow(index, rows) {
      let seed = rows[index].device_seed;
      let devid = rows[index].id;
      this.$prompt("New SEED:"+seed+"  INDEX:"+index, "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        inputPattern: /^(?!\d+$)[\da-zA-Z]+$/,
        inputErrorMessage: "格式不正确"
      })
        .then(({ value }) => {
          if (value.length != 32) {
            this.$message({
              type: "info",
              message: "输入编码不正确 请认真输入"
            });
            return;
          }
          let devid = rows[index].id;
          let data = new FormData();
          data.append("id", sessionStorage.getItem("id"));
          data.append("token", sessionStorage.getItem("token"));
          data.append("newsn", value );
          data.append("devid"  , devid  );
          axios
            .post("/user/resn", data )
            .then(
              function(res) {
                if (res.data.res) {
                  this.$notify.success({
                    title: "Info",
                    message: "修改成功",
                    showClose: false
                  });
                  rows.splice(index, 1);
                  this.reflash_devlist();
                } else {
                  this.$notify.success({
                    title: "Info",
                    message: "修改失败",
                    showClose: false
                  });
                }
              }.bind(this)
            )
            .catch(function(res) {
              console.log(res);
            });
        })
        .catch(() => {
          this.$message({
            type: "info",
            message: "取消输入"
          });
        });
    },

    rerqRow(index, rows) {
