    },
    handleClose_adddevice3() {
      this.dialogVisible_adddevice3 = false;
    },
    tableRowClassName({ row, rowIndex }) {
      // if (rowIndex%4=== 1) {
      //   return "warning-row";
      // } else if (rowIndex%4=== 3) {
      //   return "success-row";
      // // }
      // console.log(rowIndex,this.tableData[rowIndex].kind,row);

      if(row.kind == 1 ){
          return "error-row";
      }else if (row.kind == 2){
          return "success-row";
      }else if(row.status > 0){
          return "success-row";
      }else{
          return "warning-row";
      }

      return "";
    },
    reflash_devlist: function() {
      this.warningSet.seedList = [];
      let data = new FormData();
      data.append("id", sessionStorage.getItem("id"));
      data.append("token", sessionStorage.getItem("token"));
      console.log(data);
      this.voldata = [];
      axios
        .post("/user/fnckukei/listmydevice",  data )
        .then(
          function(res) {
            if (res.data.res) {
              this.tableData = res.data.results;
              this.tableDatatmp = res.data.results;
              this.has_warning = false;
              this.voldata = [];
              for(var i in this.tableData){
                if(this.tableData[i].kind == 1 ){

                   this.has_warning = true;
                }
                if(this.tableData[i].vol ==  -1){
                    this.tableData[i].vol =  0;
                }
                this.voldata.push({
                	key: this.tableData[i].device_seed,
                	label: this.tableData[i].devname
                });
              }

              this.$forceUpdate();
            }
          }.bind(this)
        )
        .catch(function(res) {
          console.log(res);
        });
    },
  }
};
</script>

