    save_task() {
      if (this.form.name == "") {
        this.$message({
          type: "warning",
          message: "任务名字不能为空"
        });
        return;
      }
      // if (this.form.nodeid == "") {
      //   this.$message({
      //     type: "warning",
      //     message: "没有选择该任务的网络节点"
      //   });
      //   return;
      // }
      if (this.form.seedlist.value.length == 0) {
        this.$message({
          type: "warning",
          message: "没有选择播放设备"
        });
        return;
      }
      if (this.form.filelist.value.length == 0) {
        this.$message({
          type: "warning",
          message: "没有选择播放的音频文件"
        });
        return;
      }
      if (this.form.startTime == null || this.form.startTime == 0) {
        this.$message({
          type: "warning",
          message: "没有选择播放开始时间"
        });
        return;
      }
      if (this.form.kind == "") {
        this.$message({
          type: "warning",
          message: "没有选择播放模式"
        });
        return;
      }

      if (!this.checked1) {
        this.form.estartDate = "";
      } else if (this.form.startDate != "") {
        var datestart = new Date(this.form.startDate);
        // console.log(datestart);
        //this.form.estartDate = parseInt(          datestart.getTime() / (3600 * 24 * 1000)        );
        this.form.estartDate = datestart.getFullYear()+"-"+datestart.getMonth()+"-"+datestart.getDate();
      } else {
        this.form.estartDate = "";
      }
      if (!this.checked2) {
        //this.form.eendDate = 0;
        this.form.eendDate = "";
      } else if (this.form.endDate != "") {
        var dateend = new Date(this.form.endDate);
        this.form.eendDate = dateend.getFullYear()+"-"+dateend.getMonth()+"-"+dateend.getDate();
      } else {
        this.form.eendDate = "";
      }
      if (this.form.kind == "1") {
        if (this.form.len < 600) {
          this.form.len = 600;
        }
      }

      if (this.form.kind == "0") {
        this.Timerpickerchange2();
        if (this.form.len < 10) {
          this.form.len = 10;
        }
        this.form.num=0;
      }

      for (var i = 0; i < this.week.length; i++) {
        if (this.week[i]) {
          this.week[i] = 1;
        } else {
          this.week[i] = 0;
        }
      }
      this.form.weekStr = "";
      for (var i = 0; i < this.week.length; i++) {
        this.form.weekStr += this.week[i];
      }
      var date = new Date(this.form.startTime);
      var h = date.getHours();
      var m = date.getMinutes();
      var s = date.getSeconds();
      var start_time =h+":"+m+":"+s;
      var j = 0;
      var len = 0;
      var arrseed = [];
      var seedidlist = this.form.seedlist.value.join("|");
      var arrfile = [];
      for (var i in this.form.filelist.value) {
        arrfile.push(this.form.filelist.value[i]);
      }
      var fileidlist = arrfile.join("|");
      let data = new FormData();
      data.append("id", sessionStorage.getItem("id"));
      data.append("token", sessionStorage.getItem("token"));
      data.append("snids", seedidlist);
      data.append("fileids", fileidlist);
      data.append("weeks", this.form.weekStr);
