		  this.form.startTime =  this.form.timepicker[0];
		  var h ,f , m, h2,f2,m2;
		  var t1 = new Date(this.form.timepicker[0]);
		  var t2 = new Date(this.form.timepicker[1]);
		  h = t1.getHours();
		  f = t1.getMinutes();
		  m = t1.getSeconds();
		  h2 = t2.getHours();
		  f2 = t2.getMinutes();
		  m2 = t2.getSeconds();
		  var k1 = h*3600+f*60+m;
		  var k2= h2*3600+f2*60+m2;
		  if(k1 == k2){
			 		this.$message({
			 			type: 'warning',
			 			message: '随机播放开始时间不能等于结束时间'
			 		});
			t2.setMinutes(t2.getMinutes()+10);
			console.log(this.form.timepicker[1]);
			console.log( t2);
			this.form.timepicker[1]=t2;
			this.form.len = 600;

		  }else if( (k2-k1)>7200 ){
			  t2.setMinutes(t1.getMinutes()+120);
			  this.form.timepicker[1]=t2;
			  console.log(this.form.timepicker[0]);
			  console.log( this.form.timepicker[1]);
			  this.form.len = 7200;
		  }else{
			  this.form.len = k2-k1;
		  }
	  },
	  handleTransfer(type, data, callback) {
	    if (type == 'left') {
	      this.form.filelist.data = this.form.filelist.data.concat(this.form.filelist.value[data]);
	    } else {
	      this.form.filelist.value = this.form.filelist.value.concat(this.form.filelist.data[data])
	    }
	    this[type + 'Data'].splice(data, 1);
	    callback(type);
	  },
	  handleSort(type, sortType, data, callback) {
	    if (!sortType || sortType == 'right') {
	      if (type == 'up') {
	        this.form.filelist.data = this.swapItems(this.form.filelist.data, data[1], data[1] - 1)
	        callback(sortType, [data[0], data[1] - 1]);
	      } else {
	        this.form.filelist.data = this.swapItems(this.form.filelist.data, data[1], data[1] + 1)
	        callback(sortType, [data[0], data[1] + 1])
	      }
	    } else if (sortType == 'left') {
	      if (type == 'up') {
	        this.form.filelist.value = this.swapItems(this.form.filelist.value, data[0], data[0] - 1)
	        callback(sortType, [data[0] - 1, data[1]]);
	      } else {
	        this.form.filelist.value = this.swapItems(this.form.filelist.value, data[0], data[0] + 1)
	        callback(sortType, [data[0] + 1, data[1]])
	      }
	    } else if (sortType == 'both') {
	      if (type == 'up') {
	        data[0] == 0 ? '' : this.form.filelist.value = this.swapItems(this.form.filelist.value, data[0], data[0] - 1)
	        data[1] == 0 ? '' : this.form.filelist.data = this.swapItems(this.form.filelist.data, data[1], data[1] - 1)
	        callback(sortType, [data[0] == 0 ? data[0] : (data[0] - 1), data[1] == 0 ?  data[1] : (data[1] - 1)]);
	      } else {
	        data[0] == (this.form.filelist.value.length - 1) ? '' : this.form.filelist.value = this.swapItems(this.form.filelist.value, data[0], data[0] + 1)
	        data[1] == (this.form.filelist.data.length - 1) ? '' : this.form.filelist.data = this.swapItems(this.form.filelist.data, data[1], data[1] + 1)
	        callback(sortType, [data[0] == (this.form.filelist.value.length - 1) ? data[0] : (data[0] + 1), data[1] == (this.form.filelist.data.length - 1) ? data[1] : (data[1] + 1)])
	      }
	    }
	  },
	  swapItems(arr, index1, index2) {
	    arr[index1] = arr.splice(index2, 1, arr[index1])[0];
	    return arr;
	  },
	rightCheck(selectionKeys, changeKeys){
            	this.tempSelectionKeys = selectionKeys;
            	if(selectionKeys.length > 0){
            		this.upDownDisable = false;
