            upData(){
				if(this.tempSelectionKeys.length > 1){
					this.$message({
						type: 'warning',
						message: '仅支持单选调顺序'
					});
					return ;
				}
            	let indexNum = 0;
            	for(let i=0; i<this.tempSelectionKeys.length; i++){
            		indexNum = this.form.filelist.value.indexOf(this.tempSelectionKeys[i])
            		if(indexNum > 0){
            			this.form.filelist.value.splice(indexNum - 1, 0, this.tempSelectionKeys[i]);
            			this.form.filelist.value.splice(indexNum + 1, 1);
            		}
            	}
            },
    downData(){
      if(this.tempSelectionKeys.length > 1){
        this.$message({
          type: 'warning',
          message: '仅支持单选调顺序'
        });
        return ;
      }
      let indexNum = 0;
      for(let i=0; i<this.tempSelectionKeys.length; i++){
        indexNum = this.form.filelist.value.indexOf(this.tempSelectionKeys[i]);
        if(indexNum > -1 && indexNum != this.form.filelist.value.length - 1){
          this.form.filelist.value.splice(indexNum + 2, 0, this.tempSelectionKeys[i]);
          this.form.filelist.value.splice(indexNum, 1);
        }
      }
